 	private Schema calculateRequestBodySchema(Components components, ParameterInfo parameterInfo, RequestBodyInfo requestBodyInfo, Schema schemaN, String paramName) {
+		System.err.println("[DEBUG] calculateRequestBodySchema called for parameter '" + paramName + "' with schema: " + schemaN);
+		// If schema is null (can happen with generic types), try to create a fallback schema
+		if (schemaN == null && parameterInfo.getMethodParameter() != null) {
