+			System.err.println("[DEBUG] Schema was null for parameter '" + paramName + "' of type '" + type + "', creating fallback schema");
+			schemaN = createFallbackSchema(type);
+			System.err.println("[DEBUG] Created fallback schema: " + schemaN);
+		}
+
 		if (schemaN != null && StringUtils.isEmpty(schemaN.getDescription()) && parameterInfo.getParameterModel() != null) {
