 			if (schemaN.get$ref() != null && schemaN.get$ref().contains(AnnotationsUtils.COMPONENTS_REF)) {
@@ -445,6 +455,91 @@ public class GenericParameterService {
 		return schemaN;
 	}

+	/**
+	 * Creates a fallback schema for types that failed to resolve.
+	 *
+	 * @param type the type
+	 * @return the schema
+	 */
+	private Schema createFallbackSchema(Type type) {
+		if (type instanceof ParameterizedType) {
+			ParameterizedType parameterizedType = (ParameterizedType) type;
+			Type rawType = parameterizedType.getRawType();
+
+			// Handle Map types
+			if (rawType instanceof Class && Map.class.isAssignableFrom((Class<?>) rawType)) {
+				ObjectSchema schema = new ObjectSchema();
+
+				// Get the value type if available
+				Type[] typeArguments = parameterizedType.getActualTypeArguments();
+				if (typeArguments.length >= 2) {
+					Type valueType = typeArguments[1];
+					Schema valueSchema = createSchemaForType(valueType);
+					schema.setAdditionalProperties(valueSchema);
+				} else {
+					// Default to object if no type arguments
+					schema.setAdditionalProperties(new ObjectSchema());
+				}
+
+				return schema;
+			}
+
+			// Handle List/Collection types
+			if (rawType instanceof Class && (List.class.isAssignableFrom((Class<?>) rawType) ||
+					java.util.Collection.class.isAssignableFrom((Class<?>) rawType))) {
+				io.swagger.v3.oas.models.media.ArraySchema arraySchema = new io.swagger.v3.oas.models.media.ArraySchema();
+
+				Type[] typeArguments = parameterizedType.getActualTypeArguments();
+				if (typeArguments.length >= 1) {
+					Type itemType = typeArguments[0];
+					Schema itemSchema = createSchemaForType(itemType);
+					arraySchema.setItems(itemSchema);
+				} else {
+					arraySchema.setItems(new ObjectSchema());
+				}
+
+				return arraySchema;
+			}
+		}
+
+		// For non-parameterized types, try to create a basic schema
+		if (type instanceof Class) {
+			Class<?> clazz = (Class<?>) type;
+			PrimitiveType primitiveType = PrimitiveType.fromType(clazz);
+			if (primitiveType != null) {
+				return primitiveType.createProperty();
+			}
+		}
+
+		// Default fallback
+		return new ObjectSchema();
+	}
+
+	/**
+	 * Creates a schema for a given type.
+	 *
+	 * @param type the type
+	 * @return the schema
+	 */
+	private Schema createSchemaForType(Type type) {
+		if (type instanceof Class) {
+			Class<?> clazz = (Class<?>) type;
+			PrimitiveType primitiveType = PrimitiveType.fromType(clazz);
+			if (primitiveType != null) {
+				return primitiveType.createProperty();
+			}
+		} else if (type instanceof WildcardType) {
+			// For wildcard types (e.g., ? extends Object), use Object schema
+			return new ObjectSchema();
+		} else if (type instanceof ParameterizedType) {
+			// Recursively handle parameterized types
+			return createFallbackSchema(type);
+		}
+
+		// Default to object schema
+		return new ObjectSchema();
+	}
+
