   355→			if (mediaType != null) {
   356→				if (mediaType.getExample() != null)
   357→					mediaTypeObject.setExample(mediaType.getExample());
   358→				if (mediaType.getExamples() != null)
   359→					mediaTypeObject.setExamples(mediaType.getExamples());
   360→				if (mediaType.getEncoding() != null)
   361→					mediaTypeObject.setEncoding(mediaType.getEncoding());
   362→			}
   363→			content.addMediaType(value, mediaTypeObject);
   364→		}
   365→		requestBody.setContent(content);
   366→	}
