   418→	private Schema calculateRequestBodySchema(Components components, ParameterInfo parameterInfo, RequestBodyInfo requestBodyInfo, Schema schemaN, String paramName) {
   419→		if (schemaN != null && StringUtils.isEmpty(schemaN.getDescription()) && parameterInfo.getParameterModel() != null) {
   420→			String description = parameterInfo.getParameterModel().getDescription();
   421→			if (schemaN.get$ref() != null && schemaN.get$ref().contains(AnnotationsUtils.COMPONENTS_REF)) {
   422→				String key = schemaN.get$ref().substring(Components.COMPONENTS_SCHEMAS_REF.length());
   423→				Schema existingSchema = components.getSchemas().get(key);
   424→				if (!StringUtils.isEmpty(description))
   425→					existingSchema.setDescription(description);
   426→			}
   427→			else
   428→				schemaN.setDescription(description);
   429→		}
   430→
   431→		if (requestBodyInfo.getMergedSchema() != null) {
   432→			requestBodyInfo.getMergedSchema().addProperty(paramName, schemaN);
   433→			schemaN = requestBodyInfo.getMergedSchema();
   434→		}
   435→		else if (parameterInfo.isRequestPart() || ParameterIn.QUERY.toString().equals(parameterInfo.getParamType()) || schemaN instanceof FileSchema || (schemaN != null && schemaN.getItems() instanceof FileSchema)) {
   436→			schemaN = new ObjectSchema().addProperty(paramName, schemaN);
   437→			requestBodyInfo.setMergedSchema(schemaN);
   438→		}
   439→		else
   440→			requestBodyInfo.addProperties(paramName, schemaN);
   441→
   442→		if (requestBodyInfo.getMergedSchema() != null && parameterInfo.isRequired())
   443→			requestBodyInfo.getMergedSchema().addRequiredItem(parameterInfo.getpName());
   444→
   445→		return schemaN;
   446→	}
