   229→	 * @param map              the map
   230→	 * @return the headers
   231→	 */
   232→	@SuppressWarnings("unchecked")
   233→	public static Collection<Parameter> getHeaders(MethodAttributes methodAttributes, Map<ParameterId, Parameter> map) {
   234→		for (Entry<String, String> entry : methodAttributes.getHeaders().entrySet()) {
   235→			StringSchema schema = new StringSchema();
   236→			if (StringUtils.isNotEmpty(entry.getValue()))
   237→				schema.addEnumItem(entry.getValue());
   238→			Parameter parameter = new Parameter().in(ParameterIn.HEADER.toString()).name(entry.getKey()).schema(schema);
   239→			ParameterId parameterId = new ParameterId(parameter);
   240→			if (map.containsKey(parameterId)) {
   241→				parameter = map.get(parameterId);
   242→				List existingEnum = null;
   243→				if (parameter.getSchema() != null && !CollectionUtils.isEmpty(parameter.getSchema().getEnum()))
   244→					existingEnum = parameter.getSchema().getEnum();
   245→				if (StringUtils.isNotEmpty(entry.getValue()) && (existingEnum == null || !existingEnum.contains(entry.getValue())))
   246→					parameter.getSchema().addEnumItemObject(entry.getValue());
   247→				parameter.setSchema(parameter.getSchema());
   248→			}
   249→			map.put(parameterId, parameter);
   250→		}
   251→		return map.values();
   252→	}
