   265→	/**
   266→	 * Build operation.
   267→	 *
   268→	 * @param handlerMethod    the handler method
   269→	 * @param requestMethod    the request method
   270→	 * @param operation        the operation
   271→	 * @param methodAttributes the method attributes
   272→	 * @param openAPI          the open api
   273→	 * @return the operation
   274→	 * @see org.springdoc.core.customizers.DelegatingMethodParameterCustomizer#customizeList(MethodParameter, List)
   275→	 * @see ParameterCustomizer#customize(Parameter, MethodParameter)
   276→	 * @see org.springdoc.core.customizers.PropertyCustomizer#customize(Schema, AnnotatedType)
   277→	 */
   278→	public Operation build(HandlerMethod handlerMethod, RequestMethod requestMethod,
   279→			Operation operation, MethodAttributes methodAttributes, OpenAPI openAPI) {
   280→		// Documentation
   281→		String operationId = operation.getOperationId() != null ? operation.getOperationId() : handlerMethod.getMethod().getName();
   282→		operation.setOperationId(operationId);
   283→		// requests
   284→		String[] pNames = this.localSpringDocParameterNameDiscoverer.getParameterNames(handlerMethod.getMethod());
   285→		MethodParameter[] parameters = handlerMethod.getMethodParameters();
   286→		String[] reflectionParametersNames = Arrays.stream(handlerMethod.getMethod().getParameters()).map(java.lang.reflect.Parameter::getName).toArray(String[]::new);
   287→		if (pNames == null || Arrays.stream(pNames).anyMatch(Objects::isNull))
   288→			pNames = reflectionParametersNames;
   289→		// Process: DelegatingMethodParameterCustomizer
   290→		parameters = DelegatingMethodParameter.customize(pNames, parameters, parameterBuilder.getOptionalDelegatingMethodParameterCustomizers(), this.defaultFlatParamObject);
   291→		RequestBodyInfo requestBodyInfo = new RequestBodyInfo();
   292→		List<Parameter> operationParameters = (operation.getParameters() != null) ? operation.getParameters() : new ArrayList<>();
   293→		Map<ParameterId, io.swagger.v3.oas.annotations.Parameter> parametersDocMap = getApiParameters(handlerMethod.getMethod());
   294→		Components components = openAPI.getComponents();
   295→
   296→		JavadocProvider javadocProvider = parameterBuilder.getJavadocProvider();
   297→
   298→		for (MethodParameter methodParameter : parameters) {
   299→			// check if query param
   300→			Parameter parameter;
   301→			io.swagger.v3.oas.annotations.Parameter parameterDoc = AnnotatedElementUtils.findMergedAnnotation(
   302→					AnnotatedElementUtils.forAnnotations(methodParameter.getParameterAnnotations()),
   303→					io.swagger.v3.oas.annotations.Parameter.class);
   304→
   305→			final String pName = methodParameter.getParameterName();
   306→			ParameterInfo parameterInfo = new ParameterInfo(pName, methodParameter, parameterBuilder, parameterDoc);
   307→
   308→			if (parameterDoc == null)
   309→				parameterDoc = parametersDocMap.get(parameterInfo.getParameterId());
   310→
   311→			if (parameterDoc == null) {
   312→				io.swagger.v3.oas.annotations.media.Schema schema = AnnotatedElementUtils.findMergedAnnotation(
   313→						AnnotatedElementUtils.forAnnotations(methodParameter.getParameterAnnotations()), io.swagger.v3.oas.annotations.media.Schema.class);
   314→				if (schema != null) {
   315→					parameterDoc = parameterBuilder.generateParameterBySchema(schema);
   316→				}
   317→			}
   318→
   319→			// use documentation as reference
   320→			if (parameterDoc != null) {
   321→				if (parameterDoc.hidden() || parameterDoc.schema().hidden())
   322→					continue;
   323→
   324→				parameter = parameterBuilder.buildParameterFromDoc(parameterDoc, components, methodAttributes.getJsonViewAnnotation(), methodAttributes.getLocale());
   325→				parameterInfo.setParameterModel(parameter);
   326→			}
   327→
   328→			if (!isParamToIgnore(methodParameter)) {
   329→				parameter = buildParams(parameterInfo, components, requestMethod, methodAttributes, openAPI.getOpenapi());
   330→				List<Annotation> parameterAnnotations = List.of(getParameterAnnotations(methodParameter));
   331→				if (isValidParameter(parameter, methodAttributes)) {
   332→					// Merge with the operation parameters
   333→					parameter = GenericParameterService.mergeParameter(operationParameters, parameter);
   334→					// Add param javadoc
   335→					if (StringUtils.isBlank(parameter.getDescription()) && javadocProvider != null) {
   336→						String paramJavadocDescription = parameterBuilder.getParamJavadoc(javadocProvider, methodParameter);
   337→						if (!StringUtils.isBlank(paramJavadocDescription)) {
   338→							parameter.setDescription(paramJavadocDescription);
   339→						}
   340→					}
   341→					// Process: applyValidationsToSchema
   342→					applyBeanValidatorAnnotations(methodParameter, parameter, parameterAnnotations, parameterInfo.isParameterObject(), openAPI.getOpenapi());
   343→				}
   344→				else if (!RequestMethod.GET.equals(requestMethod) || OpenApiVersion.OPENAPI_3_1.getVersion().equals(openAPI.getOpenapi())) {
   345→					if (operation.getRequestBody() != null)
   346→						requestBodyInfo.setRequestBody(operation.getRequestBody());
   347→					// Process: PropertyCustomizer
   348→					requestBodyService.calculateRequestBodyInfo(components, methodAttributes,
   349→							parameterInfo, requestBodyInfo);
   350→					applyBeanValidatorAnnotations(requestBodyInfo.getRequestBody(), parameterAnnotations, methodParameter.isOptional());
   351→				}
   352→				// Process: ParameterCustomizer
   353→				customiseParameter(parameter, parameterInfo, operationParameters);
   354→			}
   355→		}
   356→
   357→		LinkedHashMap<ParameterId, Parameter> map = getParameterLinkedHashMap(components, methodAttributes, operationParameters, parametersDocMap);
   358→		RequestBody requestBody = requestBodyInfo.getRequestBody();
   359→		// support form-data
   360→		if (defaultSupportFormData && requestBody != null
   361→				&& requestBody.getContent() != null
   362→				&& requestBody.getContent().containsKey(MULTIPART_FORM_DATA_VALUE)) {
   363→			Iterator<Entry<ParameterId, Parameter>> it = map.entrySet().iterator();
   364→			while (it.hasNext()) {
   365→				Entry<ParameterId, Parameter> entry = it.next();
   366→				Parameter parameter = entry.getValue();
   367→				if (!ParameterIn.PATH.toString().equals(parameter.getIn()) && !ParameterIn.HEADER.toString().equals(parameter.getIn())
   368→						&& !ParameterIn.COOKIE.toString().equals(parameter.getIn())) {
   369→					Schema<?> itemSchema;
   370→					if (parameter.getSchema() != null) {
   371→						itemSchema = parameter.getSchema();
   372→					}
   373→					else {
   374→						itemSchema = new Schema<>();
   375→						itemSchema.setName(entry.getKey().getpName());
   376→					}
   377→					if (StringUtils.isNotEmpty(parameter.getDescription()))
   378→						itemSchema.setDescription(parameter.getDescription());
   379→					if (parameter.getExample() != null)
   380→						itemSchema.setExample(parameter.getExample());
   381→					if (parameter.getDeprecated() != null)
   382→						itemSchema.setDeprecated(parameter.getDeprecated());
   383→					requestBodyInfo.addProperties(entry.getKey().getpName(), itemSchema);
   384→					it.remove();
   385→				}
   386→			}
   387→		}
   388→		setParams(operation, new ArrayList<>(map.values()), requestBodyInfo);
   389→		return operation;
   390→	}
