   392→	/**
   393→	 * Gets parameter linked hash map.
   394→	 *
   395→	 * @param components          the components
   396→	 * @param methodAttributes    the method attributes
   397→	 * @param operationParameters the operation parameters
   398→	 * @param parametersDocMap    the parameters doc map
   399→	 * @return the parameter linked hash map
   400→	 */
   401→	private LinkedHashMap<ParameterId, Parameter> getParameterLinkedHashMap(Components components, MethodAttributes methodAttributes, List<Parameter> operationParameters, Map<ParameterId, io.swagger.v3.oas.annotations.Parameter> parametersDocMap) {
   402→		LinkedHashMap<ParameterId, Parameter> map = operationParameters.stream().collect(Collectors.toMap(ParameterId::new, parameter -> parameter, (u, v) -> {
   403→			throw new IllegalStateException(String.format("Duplicate key %s", u));
   404→		}, LinkedHashMap::new));
   405→
   406→		for (Entry<ParameterId, io.swagger.v3.oas.annotations.Parameter> entry : parametersDocMap.entrySet()) {
   407→			ParameterId parameterId = entry.getKey();
   408→			if (parameterId != null && !map.containsKey(parameterId) && !entry.getValue().hidden()) {
   409→				Parameter parameter = parameterBuilder.buildParameterFromDoc(entry.getValue(), components, methodAttributes.getJsonViewAnnotation(), methodAttributes.getLocale());
   410→				//proceed with the merge if possible
   411→				if (map.containsKey(parameterId)) {
   412→					GenericParameterService.mergeParameter(map.get(parameterId), parameter);
   413→					map.put(parameterId, parameter);
   414→				}
   415→				else {
   416→					long mumParamsWithName = map.keySet().stream().filter(parameterId1 -> parameterId.getpName().equals(parameterId1.getpName())).count();
   417→					long mumParamsDocWithName = parametersDocMap.keySet().stream().filter(parameterId1 -> parameterId.getpName().equals(parameterId1.getpName())).count();
   418→					if (mumParamsWithName == 1 && mumParamsDocWithName == 1) {
   419→						Optional<ParameterId> parameterIdWithSameNameOptional = map.keySet().stream().filter(parameterId1 -> parameterId.getpName().equals(parameterId1.getpName())).findAny();
   420→						parameterIdWithSameNameOptional.ifPresent(parameterIdWithSameName -> {
   421→							GenericParameterService.mergeParameter(map.get(parameterIdWithSameName), parameter);
   422→							map.put(parameterIdWithSameName, parameter);
   423→						});
   424→					}
   425→					else
   426→						map.put(parameterId, parameter);
   427→				}
   428→			}
   429→		}
   430→
   431→		getHeaders(methodAttributes, map);
   432→		map.forEach((parameterId, parameter) -> {
   433→			if (StringUtils.isBlank(parameter.getIn()) && StringUtils.isBlank(parameter.get$ref()))
   434→				parameter.setIn(ParameterIn.QUERY.toString());
   435→		});
   436→		return map;
   437→	}
