   439→	/**
   440→	 * Customise parameter parameter.
   441→	 *
   442→	 * @param parameter           the parameter
   443→	 * @param parameterInfo       the parameter info
   444→	 * @param operationParameters the operation parameters
   445→	 */
   446→	protected void customiseParameter(Parameter parameter, ParameterInfo parameterInfo, List<Parameter> operationParameters) {
   447→		if (parameterCustomizers.isPresent()) {
   448→			List<ParameterCustomizer> parameterCustomizerList = parameterCustomizers.get();
   449→			int index = operationParameters.indexOf(parameter);
   450→			for (ParameterCustomizer parameterCustomizer : parameterCustomizerList)
   451→				parameter = parameterCustomizer.customize(parameter, parameterInfo.getMethodParameter());
   452→			if (index != -1) {
   453→				if (parameter == null)
   454→					operationParameters.remove(index);
   455→				else
   456→					operationParameters.set(index, parameter);
   457→			}
   458→		}
   459→	}
