   461→	/**
   462→	 * Is param to ignore boolean.
   463→	 *
   464→	 * @param parameter the parameter
   465→	 * @return the boolean
   466→	 */
   467→	public boolean isParamToIgnore(MethodParameter parameter) {
   468→		if (SpringDocAnnotationsUtils.isAnnotationToIgnore(parameter))
   469→			return true;
   470→		if (isRequiredAnnotation(parameter))
   471→			return false;
   472→		if (isRequestBodyWithMapType(parameter))
   473→			return false;
   474→		return isRequestTypeToIgnore(parameter.getParameterType());
   475→	}
