   477→	/**
   478→	 * Is required annotation boolean.
   479→	 *
   480→	 * @param parameter the parameter
   481→	 * @return the boolean
   482→	 */
   483→	private boolean isRequiredAnnotation(MethodParameter parameter) {
   484→		RequestParam requestParam = parameter.getParameterAnnotation(RequestParam.class);
   485→		PathVariable pathVariable = parameter.getParameterAnnotation(PathVariable.class);
   486→		org.springframework.web.bind.annotation.RequestBody requestBody = parameter.getParameterAnnotation(org.springframework.web.bind.annotation.RequestBody.class);
   487→		return (requestParam != null && requestParam.required())
   488→				|| (pathVariable != null && pathVariable.required())
   489→				|| (requestBody != null && requestBody.required());
   490→	}
