   492→	/**
   493→	 * Is request body with map type
   494→	 *
   495→	 * @param parameter the parameter
   496→	 * @return the boolean
   497→	 */
   498→	private boolean isRequestBodyWithMapType(MethodParameter parameter) {
   499→		// Exclude parameters from the Actuator package
   500→		if (parameter.getContainingClass().getPackageName().startsWith("org.springframework.boot.actuate")) {
   501→			return false;
   502→		}
   503→		// Check for @RequestBody annotation
   504→		org.springframework.web.bind.annotation.RequestBody requestBody = parameter.getParameterAnnotation(org.springframework.web.bind.annotation.RequestBody.class);
   505→		if (requestBody == null) {
   506→			return false;
   507→		}
   508→		// Check if the parameter type is assignable to Map
   509→		Class<?> parameterType = parameter.getParameterType();
   510→		return Map.class.isAssignableFrom(parameterType);
   511→	}
