   521→		if (!CollectionUtils.isEmpty(operationParameters))
   522→			operation.setParameters(operationParameters);
   523→		if (requestBodyInfo.getRequestBody() != null)
   524→			operation.setRequestBody(requestBodyInfo.getRequestBody());
