   538→	/**
   539→	 * Build params parameter.
   540→	 *
   541→	 * @param parameterInfo    the parameter info
   542→	 * @param components       the components
   543→	 * @param requestMethod    the request method
   544→	 * @param methodAttributes the method attributes
   545→	 * @param openApiVersion   the open api version
   546→	 * @return the parameter
   547→	 */
   548→	public Parameter buildParams(ParameterInfo parameterInfo, Components components,
   549→			RequestMethod requestMethod, MethodAttributes methodAttributes, String openApiVersion) {
   550→		MethodParameter methodParameter = parameterInfo.getMethodParameter();
   551→		if (parameterInfo.getParamType() != null) {
   552→			if (!ValueConstants.DEFAULT_NONE.equals(parameterInfo.getDefaultValue()))
   553→				parameterInfo.setRequired(false);
   554→			else
   555→				parameterInfo.setDefaultValue(null);
   556→			return this.buildParam(parameterInfo, components, methodAttributes.getJsonViewAnnotation());
   557→		}
   558→		// By default
   559→		if (!isRequestBodyParam(requestMethod, parameterInfo, openApiVersion, methodAttributes)) {
   560→			parameterInfo.setRequired(!((DelegatingMethodParameter) methodParameter).isNotRequired() && !methodParameter.isOptional());
   561→			parameterInfo.setDefaultValue(null);
   562→			return this.buildParam(parameterInfo, components, methodAttributes.getJsonViewAnnotation());
   563→		}
   564→		return null;
   565→	}
