   567→	/**
   568→	 * Build param parameter.
   569→	 *
   570→	 * @param parameterInfo the parameter info
   571→	 * @param components    the components
   572→	 * @param jsonView      the json view
   573→	 * @return the parameter
   574→	 */
   575→	public Parameter buildParam(ParameterInfo parameterInfo, Components components, JsonView jsonView) {
   576→		Parameter parameter = parameterInfo.getParameterModel();
   577→		String name = parameterInfo.getpName();
   578→
   579→		if (parameter == null) {
   580→			parameter = new Parameter();
   581→			parameterInfo.setParameterModel(parameter);
   582→		}
   583→
   584→		if (StringUtils.isBlank(parameter.getName()))
   585→			parameter.setName(name);
   586→
   587→		if (StringUtils.isBlank(parameter.getIn()))
   588→			parameter.setIn(parameterInfo.getParamType());
   589→
   590→		if (parameter.getRequired() == null)
   591→			parameter.setRequired(parameterInfo.isRequired());
   592→
   593→		if (containsDeprecatedAnnotation(parameterInfo.getMethodParameter().getParameterAnnotations()))
   594→			parameter.setDeprecated(true);
   595→
   596→		if (parameter.getSchema() == null && parameter.getContent() == null) {
   597→			Schema<?> schema = parameterBuilder.calculateSchema(components, parameterInfo, null,
   598→					jsonView);
   599→			if (parameterInfo.getDefaultValue() != null && schema != null) {
   600→				Object defaultValue = parameterInfo.getDefaultValue();
   601→				// Cast default value
   602→				PrimitiveType primitiveType = PrimitiveType.fromTypeAndFormat(schema.getType(), schema.getFormat());
   603→				if (primitiveType != null) {
   604→					Schema<?> primitiveSchema = primitiveType.createProperty();
   605→					primitiveSchema.setDefault(parameterInfo.getDefaultValue());
   606→					defaultValue = primitiveSchema.getDefault();
   607→				}
   608→				schema.setDefault(defaultValue);
   609→			}
   610→			parameter.setSchema(schema);
   611→		}
   612→		return parameter;
   613→	}
   614→
   615→	/**
   616→	 * Apply bean validator annotations.
   617→	 *
   618→	 * @param methodParameter   the method parameter
   619→	 * @param parameter         the parameter
   620→	 * @param annotations       the annotations
   621→	 * @param isParameterObject the is parameter object
   622→	 * @param openapiVersion    the openapi version
   623→	 */
   624→	public void applyBeanValidatorAnnotations(final MethodParameter methodParameter, final Parameter parameter, final List<Annotation> annotations, final boolean isParameterObject, String openapiVersion) {
   625→		boolean annotatedNotNull = annotations != null && SchemaUtils.annotatedNotNull(annotations);
   626→		if (annotatedNotNull && !isParameterObject) {
   627→			parameter.setRequired(true);
   628→		}
   629→		if (annotations != null) {
   630→			Schema<?> schema = parameter.getSchema();
   631→			SchemaUtils.applyValidationsToSchema(schema, annotations, openapiVersion);
   632→			if (schema instanceof ArraySchema && methodParameter instanceof DelegatingMethodParameter mp) {
   633→				java.lang.reflect.AnnotatedType annotatedType = null;
   634→				if (isParameterObject) {
   635→					Field field = mp.getField();
   636→					if (field != null) {
   637→						annotatedType = field.getAnnotatedType();
   638→					}
   639→				}
   640→				else {
   641→					java.lang.reflect.Parameter param = mp.getParameter();
   642→					annotatedType = param.getAnnotatedType();
   643→				}
   644→				if (annotatedType instanceof AnnotatedParameterizedType paramType) {
   645→					java.lang.reflect.AnnotatedType[] typeArgs = paramType.getAnnotatedActualTypeArguments();
   646→					for (java.lang.reflect.AnnotatedType typeArg : typeArgs) {
   647→						List<Annotation> genericAnnotations = Arrays.stream(typeArg.getAnnotations()).toList();
   648→						SchemaUtils.applyValidationsToSchema(schema.getItems(), genericAnnotations, openapiVersion);
   649→					}
   650→				}
   651→			}
   652→		}
   653→	}
   654→
   655→	/**
   656→	 * Apply bean validator annotations.
   657→	 *
   658→	 * @param requestBody the request body
   659→	 * @param annotations the annotations
   660→	 * @param isOptional  the is optional
   661→	 */
   662→	public void applyBeanValidatorAnnotations(final RequestBody requestBody, final List<Annotation> annotations, boolean isOptional) {
   663→		Map<String, Annotation> annos = new HashMap<>();
   664→		boolean springRequestBodyRequired = false;
   665→		boolean swaggerRequestBodyRequired = false;
   666→		if (!CollectionUtils.isEmpty(annotations)) {
   667→			annotations.forEach(annotation -> annos.put(annotation.annotationType().getSimpleName(), annotation));
   668→			springRequestBodyRequired = annotations.stream()
   669→					.filter(annotation -> org.springframework.web.bind.annotation.RequestBody.class.equals(annotation.annotationType()))
   670→					.anyMatch(annotation -> ((org.springframework.web.bind.annotation.RequestBody) annotation).required());
   671→			swaggerRequestBodyRequired = annotations.stream()
   672→					.filter(annotation -> io.swagger.v3.oas.annotations.parameters.RequestBody.class.equals(annotation.annotationType()))
   673→					.anyMatch(annotation -> ((io.swagger.v3.oas.annotations.parameters.RequestBody) annotation).required());
   674→		}
   675→		boolean validationExists = SchemaUtils.annotatedNotNull(annos.values().stream().toList());
   676→
   677→		if (validationExists || (!isOptional && (springRequestBodyRequired || swaggerRequestBodyRequired)))
   678→			requestBody.setRequired(true);
   679→	}
   680→
   681→	/**
   682→	 * Gets request body builder.
   683→	 *
   684→	 * @return the request body builder
   685→	 */
   686→	public RequestBodyService getRequestBodyBuilder() {
   687→		return requestBodyService;
   688→	}
   689→
   690→	/**
   691→	 * Is default flat param object boolean.
   692→	 *
   693→	 * @return the boolean
   694→	 */
   695→	public boolean isDefaultFlatParamObject() {
   696→		return defaultFlatParamObject;
   697→	}
   698→
   699→	/**
   700→	 * Gets parameter builder.
   701→	 *
   702→	 * @return the parameter builder
   703→	 */
   704→	public GenericParameterService getParameterBuilder() {
   705→		return parameterBuilder;
   706→	}
   707→
   708→	/**
   709→	 * Gets api parameters.
   710→	 *
   711→	 * @param method the method
   712→	 * @return the api parameters
   713→	 */
   714→	private Map<ParameterId, io.swagger.v3.oas.annotations.Parameter> getApiParameters(Method method) {
   715→		Class<?> declaringClass = method.getDeclaringClass();
   716→
   717→		Set<Parameters> apiParametersDoc = AnnotatedElementUtils.findAllMergedAnnotations(method, Parameters.class);
   718→		LinkedHashMap<ParameterId, io.swagger.v3.oas.annotations.Parameter> apiParametersMap = apiParametersDoc.stream().flatMap(x -> Stream.of(x.value())).collect(Collectors.toMap(ParameterId::new, x -> x, (e1, e2) -> e2, LinkedHashMap::new));
   719→
   720→		Set<Parameters> apiParametersDocDeclaringClass = AnnotatedElementUtils.findAllMergedAnnotations(declaringClass, Parameters.class);
   721→		LinkedHashMap<ParameterId, io.swagger.v3.oas.annotations.Parameter> apiParametersDocDeclaringClassMap = apiParametersDocDeclaringClass.stream().flatMap(x -> Stream.of(x.value())).collect(Collectors.toMap(ParameterId::new, x -> x, (e1, e2) -> e2, LinkedHashMap::new));
   722→		apiParametersMap.putAll(apiParametersDocDeclaringClassMap);
   723→
   724→		Set<io.swagger.v3.oas.annotations.Parameter> apiParameterDoc = AnnotatedElementUtils.findAllMergedAnnotations(method, io.swagger.v3.oas.annotations.Parameter.class);
   725→		LinkedHashMap<ParameterId, io.swagger.v3.oas.annotations.Parameter> apiParameterDocMap = apiParameterDoc.stream().collect(Collectors.toMap(ParameterId::new, x -> x, (e1, e2) -> e2, LinkedHashMap::new));
   726→		apiParametersMap.putAll(apiParameterDocMap);
   727→
   728→		Set<io.swagger.v3.oas.annotations.Parameter> apiParameterDocDeclaringClass = AnnotatedElementUtils.findAllMergedAnnotations(declaringClass, io.swagger.v3.oas.annotations.Parameter.class);
   729→		LinkedHashMap<ParameterId, io.swagger.v3.oas.annotations.Parameter> apiParameterDocDeclaringClassMap = apiParameterDocDeclaringClass.stream().collect(Collectors.toMap(ParameterId::new, x -> x, (e1, e2) -> e2, LinkedHashMap::new));
   730→		apiParametersMap.putAll(apiParameterDocDeclaringClassMap);
   731→
   732→		return apiParametersMap;
   733→	}
   734→
   735→	/**
   736→	 * Is RequestBody param boolean.
   737→	 *
   738→	 * @param requestMethod    the request method
   739→	 * @param parameterInfo    the parameter info
   740→	 * @param openApiVersion   the open api version
   741→	 * @param methodAttributes the method attributes
   742→	 * @return the boolean
   743→	 */
   744→	private boolean isRequestBodyParam(RequestMethod requestMethod, ParameterInfo parameterInfo, String openApiVersion, MethodAttributes methodAttributes) {
   745→		MethodParameter methodParameter = parameterInfo.getMethodParameter();
   746→		DelegatingMethodParameter delegatingMethodParameter = (DelegatingMethodParameter) methodParameter;
   747→		boolean isBodyAllowed = !RequestMethod.GET.equals(requestMethod) || OpenApiVersion.OPENAPI_3_1.getVersion().equals(openApiVersion);
   748→
   749→		return (isBodyAllowed && (parameterInfo.getParameterModel() == null || parameterInfo.getParameterModel().getIn() == null) && !delegatingMethodParameter.isParameterObject())
   750→				&&
   751→				(checkRequestBodyAnnotation(methodParameter)
   752→						|| checkOperationRequestBody(methodParameter)
   753→						|| checkFile(methodParameter)
   754→						|| Arrays.asList(methodAttributes.getMethodConsumes()).contains(MULTIPART_FORM_DATA_VALUE));
   755→	}
   756→
   757→	/**
   758→	 * Checks whether Swagger's or Spring's RequestBody annotation is present on a parameter or method
   759→	 *
   760→	 * @param methodParameter the method parameter
   761→	 * @return the boolean
   762→	 */
   763→	private boolean checkRequestBodyAnnotation(MethodParameter methodParameter) {
   764→		return methodParameter.hasParameterAnnotation(org.springframework.web.bind.annotation.RequestBody.class)
   765→				|| methodParameter.hasParameterAnnotation(io.swagger.v3.oas.annotations.parameters.RequestBody.class)
   766→				|| AnnotatedElementUtils.isAnnotated(Objects.requireNonNull(methodParameter.getParameter()), io.swagger.v3.oas.annotations.parameters.RequestBody.class)
   767→				|| AnnotatedElementUtils.isAnnotated(Objects.requireNonNull(methodParameter.getMethod()), io.swagger.v3.oas.annotations.parameters.RequestBody.class);
   768→	}
   769→
   770→	/**
   771→	 * Check file boolean.
   772→	 *
   773→	 * @param methodParameter the method parameter
   774→	 * @return the boolean
   775→	 */
   776→	private boolean checkFile(MethodParameter methodParameter) {
   777→		if (methodParameter.getParameterAnnotation(RequestPart.class) != null)
   778→			return true;
   779→		else if (methodParameter.getParameterAnnotation(RequestParam.class) != null) {
   780→			return isFile(methodParameter.getParameterType());
   781→		}
   782→		return false;
   783→	}
   784→
   785→	/**
   786→	 * Check operation request body boolean.
   787→	 *
   788→	 * @param methodParameter the method parameter
   789→	 * @return the boolean
   790→	 */
   791→	private boolean checkOperationRequestBody(MethodParameter methodParameter) {
   792→		if (AnnotatedElementUtils.findMergedAnnotation(Objects.requireNonNull(methodParameter.getMethod()), io.swagger.v3.oas.annotations.Operation.class) != null) {
   793→			io.swagger.v3.oas.annotations.Operation operation = AnnotatedElementUtils.findMergedAnnotation(Objects.requireNonNull(methodParameter.getMethod()), io.swagger.v3.oas.annotations.Operation.class);
   794→			if (operation != null) {
   795→				io.swagger.v3.oas.annotations.parameters.RequestBody requestBody = operation.requestBody();
   796→				if (StringUtils.isNotBlank(requestBody.description()))
   797→					return true;
   798→				else if (StringUtils.isNotBlank(requestBody.ref()))
   799→					return true;
   800→				else if (requestBody.required())
   801→					return true;
   802→				else if (requestBody.useParameterTypeSchema())
   803→					return true;
   804→				else if (requestBody.content().length > 0)
   805→					return true;
   806→				else
   807→					return requestBody.extensions().length > 0;
   808→			}
   809→		}
   810→		return false;
   811→	}
   812→
   813→}
