    52→import io.swagger.v3.oas.models.responses.ApiResponse;
    53→import io.swagger.v3.oas.models.responses.ApiResponses;
    54→import org.apache.commons.lang3.StringUtils;
    55→import org.springdoc.core.models.MethodAttributes;
    56→import org.springdoc.core.providers.JavadocProvider;
    57→import org.springdoc.core.utils.PropertyResolverUtils;
    58→import org.springdoc.core.utils.SpringDocAnnotationsUtils;
    59→
    60→import org.springframework.core.annotation.AnnotationUtils;
    61→import org.springframework.util.CollectionUtils;
    62→
    63→import static org.springdoc.core.utils.Constants.DELETE_METHOD;
    64→import static org.springdoc.core.utils.Constants.GET_METHOD;
    65→import static org.springdoc.core.utils.Constants.HEAD_METHOD;
    66→import static org.springdoc.core.utils.Constants.OPTIONS_METHOD;
    67→import static org.springdoc.core.utils.Constants.PATCH_METHOD;
    68→import static org.springdoc.core.utils.Constants.POST_METHOD;
    69→import static org.springdoc.core.utils.Constants.PUT_METHOD;
    70→import static org.springdoc.core.utils.Constants.TRACE_METHOD;
    71→
    72→/**
    73→ * The type Operation builder.
    74→ *
    75→ * @author bnasslahsen
    76→ */
    77→public class OperationService {
    78→
    79→	/**
    80→	 * The Parameter builder.
    81→	 */
    82→	private final GenericParameterService parameterBuilder;
    83→
    84→	/**
    85→	 * The Request body builder.
    86→	 */
    87→	private final RequestBodyService requestBodyService;
    88→
    89→	/**
    90→	 * The Security parser.
    91→	 */
    92→	private final SecurityService securityParser;
    93→
    94→	/**
    95→	 * The Property resolver utils.
    96→	 */
    97→	private final PropertyResolverUtils propertyResolverUtils;
    98→
    99→	/**
   100→	 * Instantiates a new Operation builder.
   101→	 *
   102→	 * @param parameterBuilder      the parameter builder
   103→	 * @param requestBodyService    the request body builder
   104→	 * @param securityParser        the security parser
   105→	 * @param propertyResolverUtils the property resolver utils
   106→	 */
   107→	public OperationService(GenericParameterService parameterBuilder, RequestBodyService requestBodyService,
   108→			SecurityService securityParser, PropertyResolverUtils propertyResolverUtils) {
   109→		super();
   110→		this.parameterBuilder = parameterBuilder;
   111→		this.requestBodyService = requestBodyService;
   112→		this.securityParser = securityParser;
   113→		this.propertyResolverUtils = propertyResolverUtils;
   114→	}
   115→
   116→	/**
   117→	 * Parse open api.
   118→	 *
   119→	 * @param apiOperation     the api operation
   120→	 * @param operation        the operation
   121→	 * @param openAPI          the open api
   122→	 * @param methodAttributes the method attributes
   123→	 * @return the open api
   124→	 */
   125→	public OpenAPI parse(io.swagger.v3.oas.annotations.Operation apiOperation,
   126→			Operation operation, OpenAPI openAPI, MethodAttributes methodAttributes) {
   127→		Components components = openAPI.getComponents();
   128→		Locale locale = methodAttributes.getLocale();
   129→		if (StringUtils.isNotBlank(apiOperation.summary()))
   130→			operation.setSummary(propertyResolverUtils.resolve(apiOperation.summary(), locale));
   131→
   132→		if (StringUtils.isNotBlank(apiOperation.description()))
   133→			operation.setDescription(propertyResolverUtils.resolve(apiOperation.description(), locale));
   134→
   135→		if (StringUtils.isNotBlank(apiOperation.operationId()))
   136→			operation.setOperationId(apiOperation.operationId());
   137→
   138→		if (apiOperation.deprecated())
   139→			operation.setDeprecated(apiOperation.deprecated());
   140→
   141→		buildTags(apiOperation, operation);
   142→
   143→		if (operation.getExternalDocs() == null)  // if not set in root annotation
   144→			AnnotationsUtils.getExternalDocumentation(apiOperation.externalDocs(), propertyResolverUtils.isOpenapi31())
   145→					.ifPresent(operation::setExternalDocs);
   146→
   147→		// servers
   148→		AnnotationsUtils.getServers(apiOperation.servers())
   149→				.ifPresent(servers -> servers.forEach(operation::addServersItem));
   150→
   151→		// build parameters
   152→		for (io.swagger.v3.oas.annotations.Parameter parameterDoc : apiOperation.parameters()) {
   153→			Parameter parameter = parameterBuilder.buildParameterFromDoc(parameterDoc, components,
   154→					methodAttributes.getJsonViewAnnotation(), locale);
   155→			operation.addParametersItem(parameter);
   156→		}
   157→
   158→		// RequestBody in Operation
   159→		requestBodyService.buildRequestBodyFromDoc(apiOperation.requestBody(), operation.getRequestBody(), methodAttributes, components, locale)
   160→				.ifPresent(operation::setRequestBody);
   161→
   162→		// build response
   163→		buildResponse(components, apiOperation, operation, methodAttributes);
   164→
   165→		// security
   166→		securityParser.buildSecurityRequirement(apiOperation.security(), operation);
   167→
   168→		// Extensions in Operation
   169→		buildExtensions(apiOperation, operation, locale);
   170→		return openAPI;
   171→	}
   172→
   173→	/**
   174→	 * Is hidden boolean.
   175→	 *
   176→	 * @param method the method
   177→	 * @return the boolean
   178→	 */
   179→	public boolean isHidden(Method method) {
   180→		io.swagger.v3.oas.annotations.Operation apiOperation = AnnotationUtils.findAnnotation(method,
   181→				io.swagger.v3.oas.annotations.Operation.class);
   182→		return (apiOperation != null && (apiOperation.hidden()))
   183→				|| (AnnotationUtils.findAnnotation(method, Hidden.class) != null);
   184→	}
   185→
   186→	/**
   187→	 * Build callbacks optional.
   188→	 *
   189→	 * @param apiCallbacks     the api callbacks
   190→	 * @param openAPI          the open api
   191→	 * @param methodAttributes the method attributes
   192→	 * @return the optional
   193→	 */
   194→	public Optional<Map<String, Callback>> buildCallbacks(
   195→			Set<io.swagger.v3.oas.annotations.callbacks.Callback> apiCallbacks, OpenAPI openAPI,
   196→			MethodAttributes methodAttributes) {
   197→		Map<String, Callback> callbacks = new LinkedHashMap<>();
   198→
   199→		boolean doBreak = false;
   200→		for (io.swagger.v3.oas.annotations.callbacks.Callback methodCallback : apiCallbacks) {
   201→			Map<String, Callback> callbackMap = new HashMap<>();
   202→			if (methodCallback == null) {
   203→				callbacks.putAll(callbackMap);
   204→				doBreak = true;
   205→			}
   206→			Callback callbackObject = new Callback();
   207→			if (!doBreak && StringUtils.isNotBlank(methodCallback.ref())) {
   208→				callbackObject.set$ref(methodCallback.ref());
   209→				callbackMap.put(methodCallback.name(), callbackObject);
   210→				callbacks.putAll(callbackMap);
   211→				doBreak = true;
   212→			}
   213→
   214→			if (doBreak)
   215→				break;
   216→
   217→			PathItem pathItemObject = new PathItem();
   218→			for (io.swagger.v3.oas.annotations.Operation callbackOperation : methodCallback.operation()) {
   219→				Operation callbackNewOperation = new Operation();
   220→				parse(callbackOperation, callbackNewOperation, openAPI, methodAttributes);
   221→				setPathItemOperation(pathItemObject, callbackOperation.method(), callbackNewOperation);
   222→			}
   223→			callbackObject.addPathItem(methodCallback.callbackUrlExpression(), pathItemObject);
   224→			callbackMap.put(methodCallback.name(), callbackObject);
   225→			callbacks.putAll(callbackMap);
   226→		}
   227→
   228→		if (CollectionUtils.isEmpty(callbacks))
   229→			return Optional.empty();
   230→		else
   231→			return Optional.of(callbacks);
   232→	}
   233→
   234→	/**
   235→	 * Sets path item operation.
   236→	 *
   237→	 * @param pathItemObject the path item object
   238→	 * @param method         the method
   239→	 * @param operation      the operation
   240→	 */
   241→	private void setPathItemOperation(PathItem pathItemObject, String method, Operation operation) {
   242→		switch (method) {
   243→			case POST_METHOD:
   244→				pathItemObject.post(operation);
   245→				break;
   246→			case GET_METHOD:
   247→				pathItemObject.get(operation);
   248→				break;
   249→			case DELETE_METHOD:
   250→				pathItemObject.delete(operation);
   251→				break;
   252→			case PUT_METHOD:
   253→				pathItemObject.put(operation);
   254→				break;
   255→			case PATCH_METHOD:
   256→				pathItemObject.patch(operation);
   257→				break;
   258→			case TRACE_METHOD:
   259→				pathItemObject.trace(operation);
   260→				break;
   261→			case HEAD_METHOD:
   262→				pathItemObject.head(operation);
   263→				break;
   264→			case OPTIONS_METHOD:
   265→				pathItemObject.options(operation);
   266→				break;
   267→			default:
   268→				// Do nothing here
   269→				break;
   270→		}
   271→	}
   272→
   273→	/**
   274→	 * Build extensions.
   275→	 *
   276→	 * @param apiOperation the api operation
   277→	 * @param operation    the operation
   278→	 * @param locale       the locale
   279→	 */
   280→	private void buildExtensions(io.swagger.v3.oas.annotations.Operation apiOperation, Operation operation, Locale locale) {
   281→		if (apiOperation.extensions().length > 0) {
   282→			Map<String, Object> extensions = AnnotationsUtils.getExtensions(propertyResolverUtils.isOpenapi31(), apiOperation.extensions());
   283→			if (propertyResolverUtils.isResolveExtensionsProperties()) {
   284→				Map<String, Object> extensionsResolved = propertyResolverUtils.resolveExtensions(locale, extensions);
   285→				extensionsResolved.forEach(operation::addExtension);
   286→			}
   287→			else {
   288→				extensions.forEach(operation::addExtension);
   289→			}
   290→		}
   291→	}
   292→
   293→	/**
   294→	 * Build tags.
   295→	 *
   296→	 * @param apiOperation the api operation
   297→	 * @param operation    the operation
   298→	 */
   299→	private void buildTags(io.swagger.v3.oas.annotations.Operation apiOperation, Operation operation) {
   300→		Optional<List<String>> mlist = getStringListFromStringArray(apiOperation.tags());
   301→		if (mlist.isPresent()) {
   302→			List<String> tags = mlist.get().stream()
   303→					.filter(t -> operation.getTags() == null
   304→							|| (operation.getTags() != null && !operation.getTags().contains(t)))
   305→					.toList();
   306→			tags.forEach(operation::addTagsItem);
   307→		}
   308→	}
   309→
   310→	/**
   311→	 * Gets api responses.
   312→	 *
   313→	 * @param responses        the responses
   314→	 * @param methodAttributes the method attributes
   315→	 * @param operation        the operation
   316→	 * @param components       the components
   317→	 * @return the api responses
   318→	 */
   319→	private Optional<ApiResponses> getApiResponses(
   320→			final io.swagger.v3.oas.annotations.responses.ApiResponse[] responses,
   321→			MethodAttributes methodAttributes, Operation operation, Components components) {
   322→
   323→		ApiResponses apiResponsesObject = new ApiResponses();
   324→		String[] classProduces = methodAttributes.getClassProduces();
   325→		String[] methodProduces = methodAttributes.getMethodProduces();
   326→
   327→		ApiResponses apiResponsesOp = operation.getResponses();
   328→
   329→		for (io.swagger.v3.oas.annotations.responses.ApiResponse response : responses) {
   330→			ApiResponse apiResponseObject = new ApiResponse();
   331→			if (StringUtils.isNotBlank(response.ref())) {
   332→				setRef(apiResponsesObject, response, apiResponseObject);
   333→				continue;
   334→			}
   335→			setDescription(response, apiResponseObject, methodAttributes.getJavadocReturn());
   336→			setExtensions(response, apiResponseObject, methodAttributes.getLocale());
   337→
   338→			buildResponseContent(methodAttributes, components, classProduces, methodProduces, apiResponsesOp, response, apiResponseObject);
   339→
   340→			SpringDocAnnotationsUtils.getHeaders(response.headers(), components, null, propertyResolverUtils.isOpenapi31()).ifPresent(apiResponseObject::headers);
   341→			// Make schema as string if empty
   342→			calculateHeader(apiResponseObject);
   343→			if (isResponseObject(apiResponseObject)) {
   344→				setLinks(response, apiResponseObject);
   345→				if (StringUtils.isNotBlank(response.responseCode())) {
   346→					apiResponsesObject.addApiResponse(response.responseCode(), apiResponseObject);
   347→				}
   348→				else {
   349→					apiResponsesObject._default(apiResponseObject);
   350→				}
   351→			}
   352→		}
   353→
   354→		return Optional.of(apiResponsesObject);
   355→	}
   356→
   357→	/**
   358→	 * Build response content.
   359→	 *
   360→	 * @param methodAttributes  the method attributes
   361→	 * @param components        the components
   362→	 * @param classProduces     the class produces
   363→	 * @param methodProduces    the method produces
   364→	 * @param apiResponsesOp    the api responses op
   365→	 * @param response          the response
   366→	 * @param apiResponseObject the api response object
   367→	 */
   368→	private void buildResponseContent(MethodAttributes methodAttributes, Components components, String[] classProduces, String[] methodProduces, ApiResponses apiResponsesOp, io.swagger.v3.oas.annotations.responses.ApiResponse response, ApiResponse apiResponseObject) {
   369→		if (apiResponsesOp == null)
   370→			SpringDocAnnotationsUtils.getContent(response.content(),
   371→							classProduces == null ? new String[0] : classProduces,
   372→							methodProduces == null ? new String[0] : methodProduces, null, components, null, propertyResolverUtils.isOpenapi31())
   373→					.ifPresent(apiResponseObject::content);
   374→		else
   375→			GenericResponseService.buildContentFromDoc(components, apiResponsesOp, methodAttributes, response, apiResponseObject, propertyResolverUtils.isOpenapi31());
   376→	}
   377→
   378→	/**
   379→	 * Is response object boolean.
   380→	 *
   381→	 * @param apiResponseObject the api response object
   382→	 * @return the boolean
   383→	 */
   384→	private boolean isResponseObject(ApiResponse apiResponseObject) {
   385→		return StringUtils.isNotBlank(apiResponseObject.getDescription()) || apiResponseObject.getContent() != null
   386→				|| apiResponseObject.getHeaders() != null;
   387→	}
   388→
   389→	/**
   390→	 * Sets links.
   391→	 *
   392→	 * @param response          the response
   393→	 * @param apiResponseObject the api response object
   394→	 */
   395→	private void setLinks(io.swagger.v3.oas.annotations.responses.ApiResponse response, ApiResponse apiResponseObject) {
   396→		Map<String, Link> links = AnnotationsUtils.getLinks(response.links(), propertyResolverUtils.isOpenapi31());
   397→		if (links.size() > 0) {
   398→			apiResponseObject.setLinks(links);
   399→		}
   400→	}
   401→
   402→	/**
   403→	 * Sets description.
   404→	 *
   405→	 * @param response          the response
   406→	 * @param apiResponseObject the api response object
   407→	 * @param javadocReturn     the javadoc return
   408→	 */
   409→	private void setDescription(io.swagger.v3.oas.annotations.responses.ApiResponse response,
   410→			ApiResponse apiResponseObject, String javadocReturn) {
   411→		if (StringUtils.isNotBlank(response.description())) {
   412→			apiResponseObject.setDescription(response.description());
   413→		}
   414→		else if (StringUtils.isNotBlank(javadocReturn)) {
   415→			apiResponseObject.setDescription(javadocReturn);
   416→		}
   417→		else {
   418→			GenericResponseService.setDescription(response.responseCode(), apiResponseObject);
   419→		}
   420→	}
   421→
   422→	/**
   423→	 * Calculate header.
   424→	 *
   425→	 * @param apiResponseObject the api response object
   426→	 */
   427→	private void calculateHeader(ApiResponse apiResponseObject) {
   428→		Map<String, Header> headers = apiResponseObject.getHeaders();
   429→		if (!CollectionUtils.isEmpty(headers)) {
   430→			for (Map.Entry<String, Header> entry : headers.entrySet()) {
   431→				Header header = entry.getValue();
   432→				if (header.getSchema() == null) {
   433→					Schema<?> schema = AnnotationsUtils.resolveSchemaFromType(String.class, null, null, propertyResolverUtils.isOpenapi31());
   434→					header.setSchema(schema);
   435→					entry.setValue(header);
   436→				}
   437→			}
   438→		}
   439→	}
   440→
   441→	/**
   442→	 * Sets ref.
   443→	 *
   444→	 * @param apiResponsesObject the api responses object
   445→	 * @param response           the response
   446→	 * @param apiResponseObject  the api response object
   447→	 */
   448→	private void setRef(ApiResponses apiResponsesObject, io.swagger.v3.oas.annotations.responses.ApiResponse response,
   449→			ApiResponse apiResponseObject) {
   450→		apiResponseObject.set$ref(response.ref());
   451→		if (StringUtils.isNotBlank(response.responseCode())) {
   452→			apiResponsesObject.addApiResponse(response.responseCode(), apiResponseObject);
   453→		}
   454→		else {
   455→			apiResponsesObject._default(apiResponseObject);
   456→		}
   457→	}
   458→
   459→	/**
   460→	 * Sets extensions.
   461→	 *
   462→	 * @param response          the response
   463→	 * @param apiResponseObject the api response object
   464→	 * @param locale            the locale
   465→	 */
   466→	private void setExtensions(io.swagger.v3.oas.annotations.responses.ApiResponse response,
   467→			ApiResponse apiResponseObject, Locale locale) {
   468→		if (response.extensions().length > 0) {
   469→			Map<String, Object> extensions = AnnotationsUtils.getExtensions(propertyResolverUtils.isOpenapi31(), response.extensions());
   470→			if (propertyResolverUtils.isResolveExtensionsProperties()) {
   471→				Map<String, Object> extensionsResolved = propertyResolverUtils.resolveExtensions(locale, extensions);
   472→				extensionsResolved.forEach(apiResponseObject::addExtension);
   473→			}
   474→			else {
   475→				extensions.forEach(apiResponseObject::addExtension);
   476→			}
   477→		}
   478→	}
   479→
   480→
   481→	/**
   482→	 * Build response.
   483→	 *
   484→	 * @param components       the components
   485→	 * @param apiOperation     the api operation
   486→	 * @param operation        the operation
   487→	 * @param methodAttributes the method attributes
   488→	 */
   489→	private void buildResponse(Components components, io.swagger.v3.oas.annotations.Operation apiOperation,
   490→			Operation operation, MethodAttributes methodAttributes) {
   491→		getApiResponses(apiOperation.responses(), methodAttributes, operation, components).ifPresent(responses -> {
   492→			if (operation.getResponses() == null) {
   493→				operation.setResponses(responses);
   494→			}
   495→			else {
   496→				responses.forEach(operation.getResponses()::addApiResponse);
   497→			}
   498→		});
   499→	}
   500→
   501→	/**
   502→	 * Gets string list from string array.
   503→	 *
   504→	 * @param array the array
   505→	 * @return the string list from string array
   506→	 */
   507→	private Optional<List<String>> getStringListFromStringArray(String[] array) {
   508→		if (array == null) {
   509→			return Optional.empty();
   510→		}
   511→		List<String> list = new ArrayList<>();
   512→		boolean isEmpty = true;
   513→		for (String value : array) {
   514→			if (StringUtils.isNotBlank(value)) {
   515→				isEmpty = false;
   516→			}
   517→			list.add(value);
   518→		}
   519→		if (isEmpty) {
   520→			return Optional.empty();
   521→		}
   522→		return Optional.of(list);
   523→	}
   524→
   525→	/**
   526→	 * Merge operation.
   527→	 *
   528→	 * @param operation      the operation
   529→	 * @param operationModel the operation model
   530→	 * @return the operation
   531→	 */
   532→	public Operation mergeOperation(Operation operation, Operation operationModel) {
   533→		if (operationModel.getOperationId().length() < operation.getOperationId().length()) {
   534→			operation.setOperationId(operationModel.getOperationId());
   535→		}
   536→
   537→		ApiResponses apiResponses = operation.getResponses();
   538→		for (Entry<String, ApiResponse> apiResponseEntry : operationModel.getResponses().entrySet()) {
   539→			if (apiResponses.containsKey(apiResponseEntry.getKey())) {
   540→				Content existingContent = apiResponses.get(apiResponseEntry.getKey()).getContent();
   541→				Content newContent = apiResponseEntry.getValue().getContent();
   542→				if (newContent != null)
   543→					newContent.forEach((mediaTypeStr, mediaType) -> SpringDocAnnotationsUtils.mergeSchema(existingContent, mediaType.getSchema(), mediaTypeStr));
   544→			}
   545→			else
   546→				apiResponses.addApiResponse(apiResponseEntry.getKey(), apiResponseEntry.getValue());
   547→		}
   548→		return operation;
   549→	}
   550→
   551→	/**
   552→	 * Gets javadoc provider.
   553→	 *
   554→	 * @return the javadoc provider
   555→	 */
   556→	public JavadocProvider getJavadocProvider() {
   557→		return parameterBuilder.getJavadocProvider();
   558→	}
   559→
   560→	/**
   561→	 * Gets propertyResolverUtils
   562→	 *
   563→	 * @return propertyResolverUtils property resolver utils
   564→	 */
   565→	public PropertyResolverUtils getPropertyResolverUtils() {
   566→		return parameterBuilder.getPropertyResolverUtils();
   567→	}
   568→}
