package test.org.springdoc.api.v30.app244;

import java.util.Map;

import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;

import org.springframework.http.MediaType;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestPart;
import org.springframework.web.bind.annotation.RestController;

@RestController
public class HelloController {

	@Operation(description = "Passing a string works")
	@PostMapping(value = "/string-works", consumes = MediaType.MULTIPART_FORM_DATA_VALUE)
	public String stringWorks(
			@Parameter(description = "A JSON object for file mapping", required = true)
			@RequestPart String fileMapping) {
		return "Received file mapping with length " + fileMapping.length();
	}

	@Operation(description = "Passing a map doesn't work")
	@PostMapping(value = "/map-works", consumes = MediaType.MULTIPART_FORM_DATA_VALUE)
	public String mapWorks(
			@Parameter(description = "A JSON object for file mapping", required = true)
			@RequestPart Map<String, Object> fileMapping) {
		return "Received file mapping with " + fileMapping.size() + " entries";
	}
}

