package test;

import io.swagger.v3.core.converter.AnnotatedType;
import io.swagger.v3.core.converter.ModelConverters;
import io.swagger.v3.core.converter.ResolvedSchema;
import io.swagger.v3.oas.models.media.Schema;

import java.lang.reflect.Type;
import java.util.Map;

public class TestSchemaExtraction {
    public static void main(String[] args) {
        try {
            System.out.println("Testing schema extraction for Map<String, Object>...");

            Type mapType = new java.lang.reflect.ParameterizedType() {
                public Type[] getActualTypeArguments() {
                    return new Type[]{String.class, Object.class};
                }
                public Type getRawType() {
                    return Map.class;
                }
                public Type getOwnerType() {
                    return null;
                }
            };

            ResolvedSchema resolvedSchema = ModelConverters.getInstance()
                .resolveAsResolvedSchema(new AnnotatedType(mapType).resolveAsRef(true));

            System.out.println("ResolvedSchema: " + resolvedSchema);
            if (resolvedSchema != null) {
                System.out.println("Schema: " + resolvedSchema.schema);
            }
        } catch (Exception e) {
            System.out.println("Exception occurred: " + e.getClass().getName());
            e.printStackTrace();
        }
    }
}

