				return primitiveType.createProperty();
			}
		} else if (type instanceof WildcardType) {
			// For wildcard types (e.g., ? extends Object), use Object schema
			return new ObjectSchema();
		} else if (type instanceof ParameterizedType) {
			// Recursively handle parameterized types
			return createFallbackSchema(type);
		}

		// Default to object schema
		return new ObjectSchema();
	}

